import{_ as t,o as a,c as i,an as s}from"./chunks/framework.ubcH7j8_.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"A.R.C.","text":"Agentic Reasoning Core","tagline":"The open-source Platform-in-a-Box for building, deploying, and orchestrating production-ready AI agents. One command. Zero weeks of infrastructure work.","actions":[{"theme":"brand","text":"Get Started","link":"/guide/getting-started"},{"theme":"alt","text":"Why A.R.C.?","link":"/guide/why-arc"},{"theme":"alt","text":"GitHub","link":"https://github.com/arc-framework/arc-platform"}]},"features":[{"icon":"🚀","title":"Platform-in-a-Box","details":"One command — `arc run --profile think` — bootstraps a full AI agent platform. Gateway, messaging, persistence, cache, and reasoning engine. All pre-wired."},{"icon":"🔓","title":"Truly Open-Source","details":"100% of the core stack is FOSS — Apache 2.0, MIT, or MPL. No BSL, no source-available fine print, no non-compete clauses. Fork it, ship it, own it."},{"icon":"🔌","title":"Modular & Composable","details":"Flat service layout composed by capability profiles. Start with `think` (core only), scale to `ultra-instinct` (all capabilities). Swap any service without rewriting agent logic."},{"icon":"🧠","title":"Two-Brain Architecture","details":"Go handles infrastructure at compiled speed. Python drives intelligence with LangGraph, Whisper, and Piper. The right tool for each layer."},{"icon":"📡","title":"Event-Driven by Default","details":"Durable streaming with Apache Pulsar (Dr. Strange) and ephemeral messaging with NATS (Flash) for real-time, distributed intelligence that scales."},{"icon":"🗄️","title":"Stateful Agents","details":"Long-term memory and semantic search with PostgreSQL + pgvector (Oracle). Agents that remember, reason over history, and learn over time."},{"icon":"☁️","title":"Cloud-Native","details":"Fully containerized, horizontally scalable, and deployable anywhere Docker runs. Local-first development, production-ready from day one."},{"icon":"📊","title":"Observability by Default","details":"OTEL traces, metrics, and structured logs built into every service. Friday Collector (OTEL) runs in every profile. SigNoz UI in `ultra-instinct`."},{"icon":"🏠","title":"Self-Hosted","details":"Your data never leaves your infrastructure. No external API dependencies for core agent logic. Air-gapped deployments supported."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1773164166000}'),n={name:"index.md"};function r(l,e,o,d,h,p){return a(),i("div",null,[...e[0]||(e[0]=[s("",9)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
